      (line: string) => line.includes(qModulePath)
    );

    // Original: qFileName set → q.js frames filtered → length 0
    // Mutated: qFileName undefined → q.js frames not filtered → length > 0
    expect(qFramesInErrorStack.length).toBe(0);

    Q.longStackSupport = false;
  });
});
